exercise.solution_code:
#include <iostream>

int value = 100;  // global

int main() {
    int input{};
    std::cin >> input;

    int value = input;  // shadows global

    // Block 1: inner value = main's value * 1
    {
        int multiplied = value * 1;  // capture BEFORE shadowing
        int value = multiplied;      // shadows main's value
        std::cout << "inner: " << value << "\n";
    }
    std::cout << "local: " << value << "\n";
    std::cout << "global: " << ::value << "\n";

    // Block 2: inner value = main's value * 2
    {
        int multiplied = value * 2;
        int value = multiplied;
        std::cout << "inner: " << value << "\n";
    }
    std::cout << "local: " << value << "\n";
    std::cout << "global: " << ::value << "\n";

    // Block 3: inner value = main's value * 3
    {
        int multiplied = value * 3;
        int value = multiplied;
        std::cout << "inner: " << value << "\n";
    }
    std::cout << "local: " << value << "\n";
    std::cout << "global: " << ::value << "\n";

    return 0;
}
